const GalleriesModule={init(){const galleriesDataEl=document.getElementById("galleries-data");if(!galleriesDataEl)return;const mapData=JSON.parse(galleriesDataEl.textContent),{perPage:perPage,totalCount:totalCount}=mapData;this.setupPagination(perPage,totalCount),this.setupModal(),this.setupClickHandlers()},setupPagination(perPage,totalCount){const galleriesPagination=document.getElementById("event-galleries-pagination");galleriesPagination.pageSizeOptions=[12,20,40],galleriesPagination.totalCount=totalCount,galleriesPagination.pageSize=perPage,galleriesPagination.paginationText="Items per page",galleriesPagination.addEventListener("insPaginationChange",this.paginationHandler)},setupModal(){this.galleriesModal=document.getElementById("galleries-modal"),this.galleriesModalBackdrop=this.galleriesModal.querySelector(".ins-backdrop-wrap"),this.galleriesCarousel=document.getElementById("galleries-carousel");document.querySelectorAll("#event-galleries .pagination-item").forEach((galleryItem=>{galleryItem.addEventListener("click",(()=>{this.galleriesCarousel.goTo(galleryItem.dataset.item-1),this.galleriesModalBackdrop.classList.remove("hide"),this.galleriesModal.style.height="calc(100vh)"}))}))},setupClickHandlers(){document.querySelectorAll("#galleries-modal *").forEach((el=>{el.addEventListener("click",(event=>{(event.target.closest("button")||event.target.closest("img"))&&event.stopPropagation()}))}));const allElements=document.querySelectorAll("#galleries-modal *");Array.from(allElements).filter((el=>!el.closest("button")&&!el.closest("img"))).forEach((el=>{el.addEventListener("click",(event=>{event.target.closest("button")||event.target.closest("img")||(this.galleriesModalBackdrop.classList.add("hide"),this.galleriesModal.style.height="0px")}))}))},showPaginatedItems(page,perPage){const cells=document.querySelectorAll(".pagination-item"),start=(page-1)*perPage+1,end=page*perPage;cells.forEach((cell=>{const itemNumber=parseInt(cell.dataset.item,10);itemNumber>=start&&itemNumber<=end?cell.classList.remove("hide"):cell.classList.add("hide")}))},paginationHandler(event){GalleriesModule.showPaginatedItems(event.detail.pageNumber,event.detail.pageSize),document.getElementById("event-galleries").scrollIntoView({behavior:"smooth"})}};window.GalleriesModule=GalleriesModule,document.addEventListener("DOMContentLoaded",(()=>{GalleriesModule.init()}));